<!DOCTYPE html>
<html lang="en">
<head>
  <meta charset="UTF-8" />
  <meta name="viewport" content="width=device-width, initial-scale=1.0" />
  <title>Kanban Board</title>
  <style>
    :root {
      --bg: #f4f6fb;
      --surface: #ffffff;
      --text: #1c2434;
      --muted: #738096;
      --border: #dfe5ef;
      --accent: #4f6df5;
      --accent-soft: #edf0ff;
      --danger: #dc4c64;
      --shadow: 0 8px 24px rgba(35, 49, 81, 0.08);
    }

    * {
      box-sizing: border-box;
    }

    body {
      margin: 0;
      min-height: 100vh;
      background: var(--bg);
      color: var(--text);
      font-family: Arial, Helvetica, sans-serif;
    }

    .app {
      width: min(1200px, calc(100% - 32px));
      margin: 0 auto;
      padding: 42px 0;
    }

    h1 {
      margin: 0 0 24px;
      font-size: clamp(1.8rem, 4vw, 2.5rem);
      letter-spacing: -0.04em;
    }

    .new-task {
      display: flex;
      gap: 10px;
      margin-bottom: 28px;
    }

    #new-card {
      flex: 1;
      min-width: 0;
      border: 1px solid var(--border);
      border-radius: 10px;
      padding: 13px 15px;
      color: var(--text);
      background: var(--surface);
      font: inherit;
      outline: none;
      box-shadow: 0 2px 8px rgba(35, 49, 81, 0.03);
    }

    #new-card:focus {
      border-color: var(--accent);
      box-shadow: 0 0 0 3px rgba(79, 109, 245, 0.15);
    }

    button {
      border: 0;
      border-radius: 10px;
      cursor: pointer;
      font: inherit;
      transition: transform 0.15s ease, background 0.15s ease;
    }

    button:active {
      transform: translateY(1px);
    }

    #add-card {
      padding: 0 19px;
      color: white;
      background: var(--accent);
      font-weight: 700;
    }

    #add-card:hover {
      background: #3f5ce1;
    }

    .board {
      display: grid;
      grid-template-columns: repeat(3, minmax(0, 1fr));
      gap: 20px;
    }

    .column {
      display: flex;
      flex-direction: column;
      min-height: 420px;
      padding: 15px;
      border: 1px solid var(--border);
      border-radius: 16px;
      background: #eaf0f8;
      transition: border-color 0.15s ease, background 0.15s ease;
    }

    .column.drag-over {
      border-color: var(--accent);
      background: var(--accent-soft);
    }

    .column-header {
      display: flex;
      align-items: center;
      justify-content: space-between;
      padding: 3px 3px 14px;
      font-size: 1rem;
      font-weight: 700;
    }

    .count {
      display: inline-grid;
      min-width: 26px;
      height: 26px;
      place-items: center;
      padding: 0 7px;
      border-radius: 999px;
      color: #526078;
      background: var(--surface);
      font-size: 0.82rem;
    }

    .card-container {
      display: flex;
      flex: 1;
      flex-direction: column;
      gap: 10px;
      min-height: 80px;
    }

    .card {
      display: flex;
      align-items: flex-start;
      justify-content: space-between;
      gap: 10px;
      padding: 14px;
      border: 1px solid rgba(217, 225, 238, 0.9);
      border-radius: 12px;
      background: var(--surface);
      box-shadow: 0 3px 10px rgba(35, 49, 81, 0.06);
      cursor: grab;
      user-select: none;
    }

    .card:active {
      cursor: grabbing;
    }

    .card.dragging {
      opacity: 0.45;
    }

    .card-title {
      overflow-wrap: anywhere;
      line-height: 1.4;
    }

    .card-del {
      flex: 0 0 auto;
      width: 28px;
      height: 28px;
      padding: 0;
      border-radius: 8px;
      color: var(--danger);
      background: #fff0f2;
      font-size: 1.15rem;
      line-height: 1;
    }

    .card-del:hover {
      background: #ffdce2;
    }

    @media (max-width: 760px) {
      .app {
        width: min(100% - 24px, 560px);
        padding: 26px 0;
      }

      .board {
        grid-template-columns: 1fr;
      }

      .column {
        min-height: 220px;
      }
    }
  </style>
</head>
<body>
  <main class="app">
    <h1>My Kanban Board</h1>

    <div class="new-task">
      <input id="new-card" type="text" placeholder="Add a new task..." aria-label="New task title" />
      <button id="add-card" type="button">Add card</button>
    </div>

    <section class="board" aria-label="Kanban board">
      <section class="column" id="col-todo" data-column="todo">
        <header class="column-header">
          <span>To Do</span>
          <span class="count" aria-label="To Do card count">0</span>
        </header>
        <div class="card-container" aria-label="To Do cards"></div>
      </section>

      <section class="column" id="col-doing" data-column="doing">
        <header class="column-header">
          <span>Doing</span>
          <span class="count" aria-label="Doing card count">0</span>
        </header>
        <div class="card-container" aria-label="Doing cards"></div>
      </section>

      <section class="column" id="col-done" data-column="done">
        <header class="column-header">
          <span>Done</span>
          <span class="count" aria-label="Done card count">0</span>
        </header>
        <div class="card-container" aria-label="Done cards"></div>
      </section>
    </section>
  </main>

  <script>
    (() => {
      const STORAGE_KEY = "kanban-board-state";
      const input = document.getElementById("new-card");
      const addButton = document.getElementById("add-card");
      const columns = [...document.querySelectorAll(".column")];
      let draggedCard = null;

      function updateCounts() {
        columns.forEach((column) => {
          const count = column.querySelectorAll(".card-container > .card").length;
          column.querySelector(".count").textContent = count;
        });
      }

      function saveBoard() {
        const cards = [];

        columns.forEach((column) => {
          const columnName = column.dataset.column;
          column.querySelectorAll(".card").forEach((card) => {
            cards.push({
              id: card.dataset.id,
              title: card.querySelector(".card-title").textContent,
              column: columnName
            });
          });
        });

        localStorage.setItem(STORAGE_KEY, JSON.stringify(cards));
      }

      function createCard(title, id = `card-${Date.now()}-${Math.random().toString(16).slice(2)}`) {
        const card = document.createElement("article");
        card.className = "card";
        card.draggable = true;
        card.dataset.id = id;

        const cardTitle = document.createElement("span");
        cardTitle.className = "card-title";
        cardTitle.textContent = title;

        const deleteButton = document.createElement("button");
        deleteButton.className = "card-del";
        deleteButton.type = "button";
        deleteButton.setAttribute("aria-label", `Delete ${title}`);
        deleteButton.textContent = "×";

        deleteButton.addEventListener("click", (event) => {
          event.stopPropagation();
          card.remove();
          updateCounts();
          saveBoard();
        });

        card.addEventListener("dragstart", (event) => {
          draggedCard = card;
          card.classList.add("dragging");
          event.dataTransfer.effectAllowed = "move";
          event.dataTransfer.setData("text/plain", card.dataset.id);
        });

        card.addEventListener("dragend", () => {
          card.classList.remove("dragging");
          columns.forEach((column) => column.classList.remove("drag-over"));
          draggedCard = null;
        });

        card.append(cardTitle, deleteButton);
        return card;
      }

      function addCard() {
        const title = input.value.trim();
        if (!title) return;

        const todoContainer = document.querySelector("#col-todo .card-container");
        todoContainer.appendChild(createCard(title));
        input.value = "";
        input.focus();
        updateCounts();
        saveBoard();
      }

      function loadBoard() {
        let savedCards;

        try {
          savedCards = JSON.parse(localStorage.getItem(STORAGE_KEY) || "[]");
        } catch {
          savedCards = [];
        }

        if (!Array.isArray(savedCards)) return;

        savedCards.forEach((savedCard) => {
          if (
            !savedCard ||
            typeof savedCard.title !== "string" ||
            !["todo", "doing", "done"].includes(savedCard.column)
          ) {
            return;
          }

          const container = document.querySelector(
            `#col-${savedCard.column} .card-container`
          );
          container.appendChild(createCard(savedCard.title, savedCard.id));
        });

        updateCounts();
      }

      addButton.addEventListener("click", addCard);

      input.addEventListener("keydown", (event) => {
        if (event.key === "Enter") addCard();
      });

      columns.forEach((column) => {
        column.addEventListener("dragover", (event) => {
          event.preventDefault();
          event.dataTransfer.dropEffect = "move";
          column.classList.add("drag-over");
        });

        column.addEventListener("dragleave", (event) => {
          if (!column.contains(event.relatedTarget)) {
            column.classList.remove("drag-over");
          }
        });

        column.addEventListener("drop", (event) => {
          event.preventDefault();
          column.classList.remove("drag-over");

          if (draggedCard) {
            column.querySelector(".card-container").appendChild(draggedCard);
            updateCounts();
            saveBoard();
          }
        });
      });

      loadBoard();
    })();
  </script>
</body>
</html>
